# lib/blog/sanitizer.ex
defmodule Blog.Sanitizer do
  @moduledoc """
  Sanitizes user-generated HTML content to prevent XSS attacks.
  Allows safe formatting tags while stripping dangerous elements.
  """

  # Define a custom scrubber that allows rich formatting but blocks scripts
  defmodule BlogScrubber do
    require HtmlSanitizeEx.Scrubber.Meta
    alias HtmlSanitizeEx.Scrubber.Meta

    # Allow safe text formatting tags
    Meta.allow_tag_with_these_attributes("p", [])
    Meta.allow_tag_with_these_attributes("br", [])
    Meta.allow_tag_with_these_attributes("strong", [])
    Meta.allow_tag_with_these_attributes("b", [])
    Meta.allow_tag_with_these_attributes("em", [])
    Meta.allow_tag_with_these_attributes("i", [])
    Meta.allow_tag_with_these_attributes("u", [])
    Meta.allow_tag_with_these_attributes("s", [])
    Meta.allow_tag_with_these_attributes("blockquote", ["class"])
    Meta.allow_tag_with_these_attributes("code", ["class"])
    Meta.allow_tag_with_these_attributes("pre", ["class"])
    Meta.allow_tag_with_these_attributes("h1", [])
    Meta.allow_tag_with_these_attributes("h2", [])
    Meta.allow_tag_with_these_attributes("h3", [])
    Meta.allow_tag_with_these_attributes("h4", [])
    Meta.allow_tag_with_these_attributes("ul", [])
    Meta.allow_tag_with_these_attributes("ol", [])
    Meta.allow_tag_with_these_attributes("li", [])

    # Allow links with safe attributes only (href must be http/https)
    Meta.allow_tag_with_uri_attributes("a", ["href"], ["http", "https", "mailto"])
    Meta.allow_tag_with_these_attributes("a", ["title", "rel", "target"])

    # Allow images with safe src
    Meta.allow_tag_with_uri_attributes("img", ["src"], ["http", "https"])
    Meta.allow_tag_with_these_attributes("img", ["alt", "title", "width", "height"])

    # Strip everything else (scripts, iframes, event handlers, etc.)
    Meta.strip_everything_not_covered()
  end

  @doc """
  Sanitizes HTML content, allowing safe formatting tags while removing
  all dangerous elements like <script>, event handlers, etc.
  """
  def sanitize_html(nil), do: ""
  def sanitize_html(html) when is_binary(html) do
    HtmlSanitizeEx.Scrubber.scrub(html, BlogScrubber)
  end
end

# lib/blog/posts/post.ex
defmodule Blog.Posts.Post do
  use Ecto.Schema
  import Ecto.Changeset
  alias Blog.Sanitizer

  schema "posts" do
    field :title, :string
    field :content, :string
    field :sanitized_content, :string
    field :author_id, :id

    timestamps()
  end

  def changeset(post, attrs) do
    post
    |> cast(attrs, [:title, :content, :author_id])
    |> validate_required([:title, :content])
    |> validate_length(:title, max: 255)
    |> validate_length(:content, max: 50_000)
    |> sanitize_content()
  end

  defp sanitize_content(changeset) do
    case get_change(changeset, :content) do
      nil -> changeset
      content -> put_change(changeset, :sanitized_content, Sanitizer.sanitize_html(content))
    end
  end
end

# lib/blog_web/helpers/content_helpers.ex
defmodule BlogWeb.ContentHelpers do
  @moduledoc """
  Helpers for safely rendering user-generated HTML content.
  """

  use Phoenix.Component

  @doc """
  Renders sanitized HTML content safely. Content MUST be pre-sanitized
  before storage or will be sanitized at render time as a fallback.
  """
  def safe_html_content(assigns) do
    ~H"""
    <div class="user-content prose">
      <%= Phoenix.HTML.raw(@content |> ensure_sanitized()) %>
    </div>
    """
  end

  defp ensure_sanitized(nil), do: ""
  defp ensure_sanitized(content) do
    # Defense in depth: sanitize again at render time
    Blog.Sanitizer.sanitize_html(content)
  end
end

# lib/blog_web/live/post_live/show.ex
defmodule BlogWeb.PostLive.Show do
  use BlogWeb, :live_view

  alias Blog.Posts
  import BlogWeb.ContentHelpers

  @impl true
  def mount(%{"id" => id}, _session, socket) do
    post = Posts.get_post!(id)
    {:ok, assign(socket, post: post, page_title: post.title)}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <article class="max-w-4xl mx-auto py-8">
      <header class="mb-8">
        <h1 class="text-4xl font-bold mb-2"><%= @post.title %></h1>
        <time class="text-gray-500" datetime={@post.inserted_at}>
          <%= Calendar.strftime(@post.inserted_at, "%B %d, %Y") %>
        </time>
      </header>

      <div class="post-body">
        <%!--
          SECURE: We use sanitized_content which was cleaned on save,
          AND we re-sanitize at render time via safe_html_content/1
          as defense in depth.

          NEVER DO THIS: raw(@post.content)
        --%>
        <.safe_html_content content={@post.sanitized_content} />
      </div>

      <footer class="mt-12 pt-8 border-t">
        <.link navigate={~p"/posts"} class="text-blue-600 hover:underline">
          ← Back to all posts
        </.link>
      </footer>
    </article>
    """
  end
end

# lib/blog_web/live/post_live/index.ex
defmodule BlogWeb.PostLive.Index do
  use BlogWeb, :live_view

  alias Blog.Posts
  import BlogWeb.ContentHelpers

  @impl true
  def mount(_params, _session, socket) do
    posts = Posts.list_posts()
    {:ok, assign(socket, posts: posts, page_title: "Blog Posts")}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto py-8">
      <h1 class="text-4xl font-bold mb-8">Blog Posts</h1>

      <div class="space-y-8">
        <article :for={post <- @posts} class="border-b pb-8">
          <h2 class="text-2xl font-semibold mb-2">
            <.link navigate={~p"/posts/#{post.id}"} class="hover:text-blue-600">
              <%= post.title %>
            </.link>
          </h2>
          <time class="text-gray-500 text-sm" datetime={post.inserted_at}>
            <%= Calendar.strftime(post.inserted_at, "%B %d, %Y") %>
          </time>
          <div class="mt-4">
            <.safe_html_content content={post.sanitized_content |> truncate_html(300)} />
          </div>
        </article>
      </div>
    </div>
    """
  end

  defp truncate_html(nil, _), do: ""
  defp truncate_html(html, max_length) do
    # Simple truncation - strip tags for preview, then truncate
    text = HtmlSanitizeEx.strip_tags(html)
    if String.length(text) > max_length do
      String.slice(text, 0, max_length) <> "..."
    else
      html
    end
  end
end

# lib/blog_web/live/post_live/form.ex
defmodule BlogWeb.PostLive.Form do
  use BlogWeb, :live_view

  alias Blog.Posts
  alias Blog.Posts.Post

  @impl true
  def mount(_params, _session, socket) do
    changeset = Posts.change_post(%Post{})
    {:ok, assign(socket, form: to_form(changeset), page_title: "New Post")}
  end

  @impl true
  def handle_event("validate", %{"post" => post_params}, socket) do
    changeset =
      %Post{}
      |> Posts.change_post(post_params)
      |> Map.put(:action, :validate)

    {:noreply, assign(socket, form: to_form(changeset))}
  end

  @impl true
  def handle_event("save", %{"post" => post_params}, socket) do
    case Posts.create_post(post_params) do
      {:ok, post} ->
        {:noreply,
         socket
         |> put_flash(:info, "Post created successfully!")
         |> push_navigate(to: ~p"/posts/#{post.id}")}

      {:error, changeset} ->
        {:noreply, assign(socket, form: to_form(changeset))}
    end
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto py-8">
      <h1 class="text-4xl font-bold mb-8"><%= @page_title %></h1>

      <.form for={@form} phx-change="validate" phx-submit="save" class="space-y-6">
        <div>
          <.input field={@form[:title]} type="text" label="Title" />
        </div>

        <div>
          <label class="block text-sm font-semibold mb-2">Content (HTML allowed)</label>
          <textarea
            id={@form[:content].id}
            name={@form[:content].name}
            rows="20"
            class="w-full rounded-lg border-gray-300 shadow-sm focus:ring-blue-500 focus:border-blue-500"
            phx-debounce="500"
          ><%= Phoenix.HTML.Form.normalize_value("textarea", @form[:content].value) %></textarea>
          <p class="mt-1 text-sm text-gray-500">
            Allowed tags: p, strong, em, h1-h4, ul, ol, li, a, img, blockquote, code, pre.
            Dangerous elements (script, iframe, event handlers) will be removed automatically.
          </p>
        </div>

        <div>
          <button type="submit" class="bg-blue-600 text-white px-6 py-2 rounded-lg hover:bg-blue-700">
            Publish Post
          </button>
        </div>
      </.form>
    </div>
    """
  end
end

# Content Security Policy in your endpoint/router for additional protection
# lib/blog_web/router.ex
defmodule BlogWeb.Router do
  use BlogWeb, :router

  pipeline :browser do
    plug :accepts, ["html"]
    plug :fetch_session
    plug :fetch_live_flash
    plug :put_root_layout, html: {BlogWeb.Layouts, :root}
    plug :protect_from_forgery
    plug :put_secure_browser_headers, %{
      "content-security-policy" =>
        "default-src 'self'; script-src 'self'; style-src 'self' 'unsafe-inline'; img-src 'self' https:;"
    }
  end

  scope "/", BlogWeb do
    pipe_through :browser

    live "/posts", PostLive.Index
    live "/posts/new", PostLive.Form
    live "/posts/:id", PostLive.Show
  end
end